class RequestMetricsHandler:
    def __init__(self):
        self.request_gauges = {} # Stores Gauge objects for each user_id-path combination

    def get_gauge(self, user_id, path):
        metric_name = f"http_requests_active_user_{user_id}_path_{self._sanitize_path(path)}"
        if (user_id, path) not in self.request_gauges:
            self.request_gauges[(user_id, path)] = Gauge(
                metric_name,
                f"Active HTTP requests for user_id '{user_id}' on path '{path}'",
                ['user_id', 'session_id', 'path']
            )
        return self.request_gauges[(user_id, path)]

    def _sanitize_path(self, path):
        # Prometheus metric names cannot contain certain characters like '/' or '.'
        # Replace them with underscores or remove them
        return path.replace('/', '_').replace('.', '_').replace('-', '_').strip('_')

